// // This module implements a 5-bit Johnson counter with an asynchronous reset. The counter shifts its state right, appending the original first output bit to the most significant bit. It resets to all ones when the reset signal is low.
module johnson_counter (
    input clk,
    input reset,
    output [4:0] q );reg [4:0] count_reg;

always @(posedge clk) begin
    if (reset)
        count_reg <= 5'b00000;
    else
        count_reg <= {count_reg[3:0], ~count_reg[4]};
end

assign q = count_reg;

endmodule
